"""# Carga de informacion"""

def descargar_y_obtener_shp(url, output_dir="data"):
    base_path = Path(output_dir)
    base_path.mkdir(parents=True, exist_ok=True)

    # 🔹 Crear carpeta única por descarga
    unique_id = str(uuid.uuid4())
    work_dir = base_path / unique_id
    work_dir.mkdir(parents=True, exist_ok=True)

    zip_path = work_dir / "archivo.zip"

    # 1. Descargar ZIP
    r = requests.get(url)
    r.raise_for_status()
    with open(zip_path, "wb") as f:
        f.write(r.content)

    # 2. Descomprimir
    with zipfile.ZipFile(zip_path, 'r') as zip_ref:
        zip_ref.extractall(work_dir)

    # 3. Buscar el .shp SOLO dentro de esta carpeta
    shp_files = list(work_dir.rglob("*.shp"))

    if not shp_files:
        raise FileNotFoundError("No se encontró ningún archivo .shp en el ZIP")

    return str(shp_files[0])

def cargar_datos(ruta, crs_destino='EPSG:4326'):
  """Función reutilizable para carga y reproyección."""
  try:
    gdf = gpd.read_file(ruta)
    return gdf.to_crs(crs_destino)
  except Exception as e:
    print(f'Error al cargar {ruta}: {e}')
  return None

