def reporte_calidad_gdf(gdf):
    """
    Genera un reporte de calidad de datos sin modificar el GeoDataFrame.
    Evalúa:
    - Valores nulos (NaN / None)
    - Strings vacíos o con espacios
    - Geometrías vacías
    """

    filas_totales = len(gdf)

    reporte = []

    for col in gdf.columns:
        serie = gdf[col]

        # Nulos
        nulos = serie.isna().sum()

        # Vacíos (solo para strings)
        vacios = 0
        if serie.dtype == "object":
            vacios = serie.astype(str).str.strip().eq("").sum()

        # Geometrías vacías
        geom_vacias = 0
        if col == gdf.geometry.name:
            geom_vacias = gdf.geometry.is_empty.sum()

        reporte.append({
            "columna": col,
            "nulos": int(nulos),
            "vacios": int(vacios),
            "geom_vacias": int(geom_vacias),
            "total_problemas": int(nulos + vacios + geom_vacias),
            "porcentaje_problemas": round((nulos + vacios + geom_vacias) / filas_totales * 100, 2)
        })

    df_reporte = pd.DataFrame(reporte)

    resumen_general = {
        "filas_totales": filas_totales,
        "columnas_con_problemas": int((df_reporte["total_problemas"] > 0).sum()),
        "total_problemas": int(df_reporte["total_problemas"].sum())
    }

    print(df_reporte)
    print(resumen_general)

