"""# Grafica de capas utilizadas"""

def graficar_capas_folium(gdf_departamento, gdf_casco, gdf_humedal):
    import folium

    # ==============================
    # 1. CRS correcto
    # ==============================
    gdf_dep_f = gdf_departamento.to_crs(epsg=4326).copy()
    gdf_casco_f = gdf_casco.to_crs(epsg=4326).copy()
    gdf_humedal_f = gdf_humedal.to_crs(epsg=4326).copy()

    # ==============================
    # 2. Centro del mapa
    # ==============================
    centro = gdf_dep_f.geometry.union_all().centroid

    # ==============================
    # 3. Crear mapa
    # ==============================
    m = folium.Map(
        location=[centro.y, centro.x],
        zoom_start=6,
        tiles="cartodbpositron",
        max_bounds=True
    )

    # ==============================
    # 4. Bounds de Perú
    # ==============================
    bounds = gdf_dep_f.total_bounds

    m.fit_bounds([
        [bounds[1], bounds[0]],  # SW
        [bounds[3], bounds[2]]   # NE
    ])

    # BLOQUEO REAL DEL MAPA
    m.options['maxBounds'] = [
        [bounds[1], bounds[0]],
        [bounds[3], bounds[2]]
    ]

    # ==============================
    # 5. Departamentos
    # ==============================
    folium.GeoJson(
        data=gdf_dep_f.__geo_interface__,
        name="Departamentos",
        style_function=lambda x: {
            "fillColor": "lightgrey",
            "color": "grey",
            "weight": 1,
            "fillOpacity": 0.2
        }
    ).add_to(m)

    # ==============================
    # 6. Cascos urbanos
    # ==============================
    folium.GeoJson(
        data=gdf_casco_f.__geo_interface__,
        name="Cascos urbanos",
        tooltip=folium.GeoJsonTooltip(
            fields=["IDCCPP"],
            aliases=["ID Casco:"]
        ),
        style_function=lambda x: {
            "fillColor": "white",
            "color": "black",
            "weight": 0.5,
            "fillOpacity": 0.2
        }
    ).add_to(m)

    # ==============================
    # 7. Humedales
    # ==============================
    folium.GeoJson(
        data=gdf_humedal_f.__geo_interface__,
        name="Humedales",
        tooltip=folium.GeoJsonTooltip(
            fields=["OBJECTID"],
            aliases=["ID Humedal:"]
        ),
        style_function=lambda x: {
            "fillColor": "green",
            "color": "green",
            "weight": 1,
            "fillOpacity": 0.6
        }
    ).add_to(m)

    # ==============================
    # 8. Control de capas
    # ==============================
    folium.LayerControl(collapsed=False).add_to(m)

    return m

graficar_capas_folium(gdf_departamentos_clean, gdf_casco_clean, gdf_humedal_clean)

"""# Estadistica Descriptiva"""

def calcular_cantidad_humedales_por_departamento(gdf_humedal, gdf_departamentos):

  gdf_dep = gdf_departamentos_clean.to_crs(epsg=32718)
  gdf_humedal = gdf_humedal_clean.to_crs(epsg=32718)

  gdf_join = gpd.sjoin(
      gdf_humedal,
      gdf_dep,
      how="inner",
      predicate="intersects"
  )

  conteo_dep = (
      gdf_join
      .groupby("DEPARTAMEN")
      .size()
      .reset_index(name="num_humedales")
      .sort_values(by="num_humedales", ascending=False)
  )

  conteo_total = gdf_dep[["DEPARTAMEN"]].merge(
      conteo_dep,
      on="DEPARTAMEN",
      how="left"
  ).fillna(0)

  return conteo_total

def graficar_cantidad_humedales_por_departamento(conteo_total):
  top10 = conteo_total.sort_values(by="num_humedales", ascending=False).head(10)

  plt.figure(figsize=(10, 6))

  plt.bar(top10["DEPARTAMEN"], top10["num_humedales"])

  plt.xticks(rotation=45, ha="right")
  plt.title("Top 10 departamentos con más humedales")
  plt.xlabel("Departamento")
  plt.ylabel("Cantidad de humedales")

  plt.tight_layout()
  plt.show()

df_conteo = calcular_cantidad_humedales_por_departamento(gdf_humedal_clean, gdf_departamentos_clean)
