def calcular_humedales_mas_grandes(gdf_humedal, gdf_dep):
  gdf_humedal = gdf_humedal_clean.to_crs(epsg=32718)
  gdf_dep = gdf_departamentos_clean.to_crs(epsg=32718)

  gdf_humedal["area_m2"] = gdf_humedal.geometry.area
  gdf_humedal["area_ha"] = gdf_humedal["area_m2"] / 10000

  top10_humedales = (
      gdf_humedal
      .sort_values(by="area_ha", ascending=False)
      .head(10)
  )

  top10_con_dep = gpd.sjoin(
      top10_humedales,
      gdf_dep,
      how="left",
      predicate="intersects"
  )

  top10_con_dep[["ECO_DETALL", "area_ha", "DEPARTAMEN"]]

  return top10_con_dep;

def graficar_humedales_mas_grandes(top10_con_dep):
    top10 = top10_con_dep.sort_values(by="area_ha", ascending=True).copy()

    top10["label"] = top10.index.astype(str) + " - " + top10["DEPARTAMEN"]

    plt.figure(figsize=(10, 6))
