def calcular_top_10_departamentos_afectados(gdf_humedales, gdf_departamentos_clean):
  gdf_dep = gdf_departamentos_clean.to_crs(epsg=32718)
  df_humedales = gdf_humedales.drop(columns=["index_right"], errors="ignore")

  humedales_dep = gpd.sjoin(
      df_humedales,
      gdf_dep,
      how="inner",
      predicate="intersects"
  )
  conteo_dep = (
      humedales_dep
      .groupby("DEPARTAMEN")
      .size()
      .reset_index(name="total_humedales")
      .sort_values(by="total_humedales", ascending=False)
  )

  conteo_total = gdf_dep[["DEPARTAMEN"]].merge(
      conteo_dep,
      on="DEPARTAMEN",
      how="left"
  ).fillna(0)

  top10 = conteo_total.sort_values(
      by="total_humedales", ascending=False
  ).head(10)

  return top10

def graficar_top_10_departamentos_afectados(top10):
  top10 = top10.sort_values("total_humedales", ascending=True)

  plt.figure()
  plt.barh(top10["DEPARTAMEN"], top10["total_humedales"])
  plt.xlabel("Humedales afectados (<5 km)")
  plt.ylabel("Departamento")
  plt.title("Top 10 departamentos más afectados")
  plt.show()

df_resultado_afectados = calcular_top_10_departamentos_afectados(humedales_cercanos, gdf_departamentos_clean)
