import matplotlib.pyplot as plt

def graficar_torta_humedales(gdf_humedal, humedales_cercanos):

    # ==============================
    # 1. CANTIDADES
    # ==============================
    total = len(gdf_humedal)
    cercanos = len(humedales_cercanos)
    no_cercanos = total - cercanos

    # ==============================
    # 2. DATOS
    # ==============================
    labels = [
        f'Humedales cercanos (≤5 km)\n{cercanos}',
        f'Humedales no cercanos\n{no_cercanos}'
    ]

    sizes = [cercanos, no_cercanos]

    # ==============================
    # 3. GRÁFICO
    # ==============================
    plt.figure(figsize=(6,6))

    plt.pie(
        sizes,
        labels=labels,
        autopct='%1.1f%%',
        startangle=90,
        wedgeprops={'edgecolor': 'black'}
    )

    plt.title('Proporción de humedales cercanos a cascos urbanos')
    plt.axis('equal')

    plt.show()

graficar_torta_humedales(gdf_humedal, humedales_cercanos)

